import React, { useState, useEffect, useRef } from 'react';

const Skills = () => {
  const [hoveredSkill, setHoveredSkill] = useState(null);
  const containerRef = useRef(null);
  const [rotation, setRotation] = useState(0);
  const [positions, setPositions] = useState([]);

  const allSkills = [
    { name: 'HTML5', icon: '🌐' },
    { name: 'CSS3', icon: '🎨' },
    { name: 'JavaScript', icon: '⚡' },
    { name: 'TypeScript', icon: '📘' },
    { name: 'React', icon: '⚛️' },
    { name: 'Next.js', icon: '▲' },
    { name: 'Tailwind CSS', icon: '💨' },
    { name: 'Redux', icon: '🔄' },
    { name: 'Framer Motion', icon: '🎬' },
    { name: 'Node.js', icon: '🟢' },
    { name: 'Express.js', icon: '🚀' },
    { name: 'MongoDB', icon: '🍃' },
    { name: 'MySQL', icon: '🐬' },
    { name: 'PostgreSQL', icon: '🐘' },
    { name: 'Firebase', icon: '🔥' },
    { name: 'JWT', icon: '🔐' },
    { name: 'REST API', icon: '🔗' },
    { name: 'Socket.io', icon: '📡' },
    { name: 'Java', icon: '☕' },
    { name: 'Python', icon: '🐍' },
    { name: 'C++', icon: '⚙️' },
    { name: 'C', icon: '🔧' },
    { name: 'C#', icon: '🎯' },
    { name: 'PHP', icon: '🐘' },
    { name: 'Git', icon: '🔀' },
    { name: 'GitHub', icon: '🐙' },
    { name: 'Docker', icon: '🐳' },
    { name: 'Linux', icon: '🐧' },
    { name: 'VS Code', icon: '💻' },
    { name: 'Postman', icon: '📮' },
    { name: 'Figma', icon: '🎯' }
  ];

  // Initialize random positions
  useEffect(() => {
    const initialPositions = allSkills.map(() => ({
      x: 10 + Math.random() * 70,
      y: 10 + Math.random() * 70,
      targetX: 10 + Math.random() * 70,
      targetY: 10 + Math.random() * 70,
      duration: 6 + Math.random() * 4,
      delay: Math.random() * 2,
      size: 55 + Math.random() * 25,
      rotation: Math.random() * 360
    }));
    setPositions(initialPositions);
  }, []);

  // Move to new positions every 5 seconds
  useEffect(() => {
    if (positions.length === 0) return;

    const interval = setInterval(() => {
      setPositions(prev => 
        prev.map(pos => ({
          ...pos,
          targetX: 8 + Math.random() * 78,
          targetY: 8 + Math.random() * 78,
          duration: 5 + Math.random() * 4,
          rotation: pos.rotation + (Math.random() - 0.5) * 20
        }))
      );
    }, 5000);

    return () => clearInterval(interval);
  }, [positions.length]);

  // Slow rotation animation
  useEffect(() => {
    const rotInterval = setInterval(() => {
      setRotation(prev => (prev + 0.1) % 360);
    }, 50);

    return () => clearInterval(rotInterval);
  }, []);

  return (
    <section id="skills" className="relative z-10 py-16 px-6 overflow-hidden min-h-screen">
      <div className="max-w-6xl mx-auto">
        <h2 className="text-sm uppercase tracking-widest text-gray-500 font-semibold mb-8">My Skills</h2>

        <div 
          ref={containerRef}
          className="relative min-h-[600px] w-full overflow-hidden rounded-3xl"
          style={{
            background: 'radial-gradient(ellipse at center, rgba(139,92,246,0.03) 0%, transparent 70%)'
          }}
        >
          {/* Floating Particles Background */}
          <div className="absolute inset-0 pointer-events-none">
            {[...Array(20)].map((_, i) => (
              <div
                key={i}
                className="absolute rounded-full bg-purple-400/5"
                style={{
                  width: 2 + Math.random() * 4,
                  height: 2 + Math.random() * 4,
                  top: `${Math.random() * 100}%`,
                  left: `${Math.random() * 100}%`,
                  animation: `floatParticle ${15 + Math.random() * 20}s linear infinite`,
                  animationDelay: `${Math.random() * 10}s`
                }}
              />
            ))}
          </div>

          {/* Skills Container */}
          <div className="relative w-full h-full flex items-center justify-center">
            {positions.map((pos, index) => {
              const skill = allSkills[index];
              if (!skill) return null;

              const isHovered = hoveredSkill === skill.name;

              return (
                <div
                  key={skill.name}
                  className="absolute cursor-pointer transition-all duration-1000 ease-in-out"
                  style={{
                    left: `${pos.x}%`,
                    top: `${pos.y}%`,
                    transform: `translate(-50%, -50%) rotate(${pos.rotation}deg)`,
                    transitionProperty: 'left, top, transform',
                    transitionDuration: `${pos.duration}s`,
                    transitionDelay: `${pos.delay}s`,
                    zIndex: isHovered ? 50 : 10,
                    opacity: isHovered ? 1 : 0.8
                  }}
                  onMouseEnter={() => setHoveredSkill(skill.name)}
                  onMouseLeave={() => setHoveredSkill(null)}
                >
                  <div
                    className="flex flex-col items-center justify-center rounded-full transition-all duration-300"
                    style={{
                      width: isHovered ? `${pos.size + 30}px` : `${pos.size}px`,
                      height: isHovered ? `${pos.size + 30}px` : `${pos.size}px`,
                      boxShadow: isHovered 
                        ? '0 0 60px rgba(139,92,246,0.4), 0 0 120px rgba(139,92,246,0.15)' 
                        : 'none',
                      background: isHovered 
                        ? 'rgba(26,31,46,0.9)' 
                        : 'rgba(26,31,46,0.2)',
                      border: isHovered 
                        ? '1.5px solid rgba(139,92,246,0.5)' 
                        : '1px solid rgba(255,255,255,0.05)',
                      transform: isHovered ? 'scale(1.2)' : 'scale(1)'
                    }}
                  >
                    <span
                      className="transition-all duration-300"
                      style={{
                        fontSize: isHovered ? '30px' : '20px',
                        filter: isHovered 
                          ? 'brightness(1.3) drop-shadow(0 0 20px rgba(139,92,246,0.3))' 
                          : 'brightness(0.8)'
                      }}
                    >
                      {skill.icon}
                    </span>

                    {isHovered && (
                      <span className="text-[9px] font-semibold text-white mt-0.5 animate-fadeIn">
                        {skill.name}
                      </span>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mt-8 glass-card rounded-2xl p-6">
          <div className="text-center">
            <div className="text-2xl font-bold text-white">2</div>
            <div className="text-[10px] text-gray-500">Projects Completed</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">-</div>
            <div className="text-[10px] text-gray-500">Happy Clients</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">-</div>
            <div className="text-[10px] text-gray-500">Years Experience</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">200</div>
            <div className="text-[10px] text-gray-500">Cups of Coffee</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">5</div>
            <div className="text-[10px] text-gray-500">Technologies Mastered</div>
          </div>
        </div>

        <div className="text-center text-gray-500 text-xs mt-4 opacity-60">
          Hover on any skill to see more ✨
        </div>
      </div>

      <style>{`
        @keyframes fadeIn {
          from {
            opacity: 0;
            transform: scale(0.8);
          }
          to {
            opacity: 1;
            transform: scale(1);
          }
        }
        .animate-fadeIn {
          animation: fadeIn 0.25s ease-out forwards;
        }

        @keyframes floatParticle {
          0% {
            transform: translateY(0px) translateX(0px);
            opacity: 0;
          }
          20% {
            opacity: 0.6;
          }
          80% {
            opacity: 0.6;
          }
          100% {
            transform: translateY(-100px) translateX(${Math.random() * 50 - 25}px);
            opacity: 0;
          }
        }

        .glass-card {
          background: rgba(17, 17, 17, 0.4);
          backdrop-filter: blur(10px);
          border: 1px solid rgba(255, 255, 255, 0.03);
          transition: all 0.3s ease;
        }

        .glass-card:hover {
          border-color: rgba(139, 92, 246, 0.1);
        }
      `}</style>
    </section>
  );
};

export default Skills;
